#include <stdio.h>
#include <string.h> // Required for strlen and strcspn
#include <ctype.h>  // Required for tolower

#define MAX_LINE_LENGTH 101 // For 100 characters + null terminator

int main() {
    char line[MAX_LINE_LENGTH];
    int vowel_count = 0;

    // Read a line of text from stdin
    // fgets is used for safer input of strings, especially with spaces
    if (fgets(line, sizeof(line), stdin) == NULL) {
        // Handle potential error or empty input gracefully
        printf("Number of vowels: 0\n");
        return 0;
    }

    // Remove the trailing newline character that fgets might read
    line[strcspn(line, "\n")] = '\0';

    // Iterate through each character in the string
    for (int i = 0; line[i] != '\0'; i++) {
        // Convert the character to lowercase to handle case-insensitivity
        char ch = tolower(line[i]);

        // Check if the character is one of the vowels
        if (ch == 'a' || ch == 'e' || ch == 'i' || ch == 'o' || ch == 'u') {
            vowel_count++;
        }
    }

    // Print the final count of vowels
    printf("Number of vowels: %d\n", vowel_count);

    return 0;
}
